let content = $input.first().json.message.content;

if (!content) {
  throw new Error("LLM response is missing or malformed");
}

// Handle both string and object cases
if (typeof content === "string") {
  content = content.trim()
    .replace(/^```json/, '')
    .replace(/^```/, '')
    .replace(/```$/, '')
    .trim();

  content = JSON.parse(content); // parse only if it was a string
}

// Now content is safely a JS object
return [
  {
    json: content
  }
];

const lineItems = $input.first().json.line_items

// Arrays to hold valid and invalid entries
const valid = [];
const invalid = [];

lineItems.forEach((item, index) => {
  const errors = [];

  // Check for required fields
  if (!item.description || item.description.trim() === '') errors.push('Missing description');
  if (!item.quantity || item.quantity.trim() === '') errors.push('Missing quantity');

  if (!item.amount || item.amount.trim() === '') errors.push('Missing amount');

  // Regex validations
  const quantityRegex = /^[0-9]+$/;
  const priceRegex = /^\d+(\.\d{1,2})?$/;

  if (item.quantity && !quantityRegex.test(item.quantity)) errors.push('Invalid quantity format');
  if (item.unit_price && !priceRegex.test(item.unit_price)) errors.push('Invalid unit_price format');
  if (item.amount && !priceRegex.test(item.amount)) errors.push('Invalid amount format');

  // Logical validation: unit_price * quantity = amount
  const quantity = parseInt(item.quantity);
  const unitPrice = parseFloat(item.unit_price);
  const amount = parseFloat(item.amount);

  if (!isNaN(quantity) && !isNaN(unitPrice) && !isNaN(amount)) {
    const expectedAmount = (unitPrice * quantity).toFixed(2);
    if (expectedAmount !== item.amount) {
      errors.push(`Amount mismatch: expected ${expectedAmount}, got ${item.amount}`);
    }
  }

  // Push to valid or invalid list
  if (errors.length === 0) {
    valid.push({
      json: {
        ...item,
        status: 'Valid'
      }
    });
  } else {
    invalid.push({
      json: {
        ...item,
        status: 'Invalid',
        errors
      }
    });
  }
});

return [...valid, ...invalid];

