={{
  JSON.stringify((() => {
    const input = $json;
    const output = {};

    // --- Part 1: Main document fields (No changes here) ---
    const textFields = ["document_number", "date", "due_date", "vendor_name", "vendor_address", "customer_name", "customer_address", "payment_method"];
    const numericFields = ["subtotal", "tax_rate", "tax_amount", "total", "cash_paid", "change_due"];
    if (input.document_type === "Receipt" || input.document_type === "Invoice") { output.document_type = input.document_type; }
    textFields.forEach(field => { if (input[field]) output[field] = input[field]; });
    numericFields.forEach(field => {
      if (input[field] !== null && input[field] !== undefined && input[field] !== '') {
        const num = parseFloat(input[field]);
        if (!isNaN(num)) output[field] = num;
      }
    });

    // --- Part 2: Process line_items with corrected logic ---
    if (Array.isArray(input.line_items)) {
      output.line_items = input.line_items.map(item => {
        const processedItem = { ...item };

        // Process 'amount' first
        const amountNum = parseFloat(processedItem.amount);
        processedItem.amount = isNaN(amountNum) ? 0 : amountNum;

        // Process 'quantity'
        const quantityNum = parseFloat(processedItem.quantity);
        // If quantity is not a valid number OR it is 0, set to 1.
        if (isNaN(quantityNum) || quantityNum === 0) {
          processedItem.quantity = 1;
        } else {
          processedItem.quantity = quantityNum;
        }

        // Process 'unit_price'
        const unitPriceNum = parseFloat(processedItem.unit_price);
        // If unit_price is not a valid number OR it is 0, set it to the amount.
        if (isNaN(unitPriceNum) || unitPriceNum === 0) {
          processedItem.unit_price = processedItem.amount;
        } else {
          processedItem.unit_price = unitPriceNum;
        }

        return processedItem;
      });
    }

    return output;
  })())
}}
